import re
from typing import Dict, Optional

class TemplateEngine:
    def __init__(self):
        self.templates: Dict[str, str] = {}

    def register(self, name: str, content: str):
        self.templates[name] = content

    def render(self, name: str, context: Dict[str, str] = None) -> str:
        context = context or {}
        content = self.templates.get(name, '')

        # Check for extends directive
        extends_match = re.match(r"\{%\s*extends\s+'(\w+)'\s*%\}", content)
        if extends_match:
            parent_name = extends_match.group(1)
            parent_content = self.templates.get(parent_name, '')
            child_content = content[extends_match.end():]

            # Extract child blocks
            child_blocks = dict(re.findall(
                r"\{%\s*block\s+(\w+)\s*%\}(.*?)\{%\s*endblock\s*%\}",
                child_content, re.DOTALL))

            # Replace parent blocks with child overrides
            def replace_block(m):
                block_name = m.group(1)
                default = m.group(2)
                return child_blocks.get(block_name, default)

            result = re.sub(
                r"\{%\s*block\s+(\w+)\s*%\}(.*?)\{%\s*endblock\s*%\}",
                replace_block, parent_content, flags=re.DOTALL)
        else:
            # Remove block tags for standalone templates
            result = re.sub(
                r"\{%\s*block\s+\w+\s*%\}(.*?)\{%\s*endblock\s*%\}",
                r'\1', content, flags=re.DOTALL)

        # Variable substitution
        for key, value in context.items():
            result = result.replace('{{ ' + key + ' }}', value)
        return result.strip()
